'use client';

import * as React from 'react';

import { cn } from '@/lib/utils';
import './index.css';

function Input({
  className,
  type = 'text',
  ...props
}: React.ComponentProps<'input'>) {
  return (
    <input
      type={type}
      data-slot="jb-input"
      className={cn(
        'jb-input flex h-7 w-[240px] min-w-0 rounded-[4px] border px-2 py-1 text-xs leading-4 font-normal outline-none transition-[background-color,border-color,color,box-shadow] duration-150 ease-in-out disabled:cursor-not-allowed',
        className,
      )}
      {...props}
    />
  );
}

export { Input };

.jb-input {
  border-color: var(--jb-input-border);
  background: var(--jb-input-bg);
  color: var(--jb-input-text);
}

.jb-input::placeholder {
  color: var(--jb-input-placeholder);
}

.jb-input:hover:not(:disabled) {
  background: var(--jb-input-bg-hover);
  border-color: var(--jb-input-border-hover);
}

.jb-input:focus-visible {
  border-color: var(--jb-input-border-active);
  box-shadow: 0 0 0 2px var(--jb-input-ring);
}

.jb-input[aria-invalid='true'] {
  border-color: var(--jb-input-border-invalid);
}

.jb-input[aria-invalid='true']:focus-visible {
  box-shadow: 0 0 0 2px var(--jb-input-ring-invalid);
}

.jb-input:disabled {
  cursor: not-allowed;
  background: var(--jb-input-bg-disabled);
  border-color: var(--jb-input-border-disabled);
  color: var(--jb-input-text-disabled);
}

.jb-input:disabled::placeholder {
  color: var(--jb-input-placeholder-disabled);
}
